import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.util.Scanner;

public class SecureXSSExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        String sanitizedName = null;
        try {
            sanitizedName = ESAPI.encoder().encodeForHTML(name);
        } catch (EncodingException e) {
            // Handle encoding exception
            System.err.println("Error occurred while sanitizing input.");
        }

        if (sanitizedName != null) {
            System.out.println("Hello, " + sanitizedName + "!");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
